public class IfElseIf {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
        int val=2;
        if(val==1)
        	System.out.println("Blue Color!");
        else if(val==2)
        	System.out.println("Red color!");
        else
        	System.out.println("Green color!");
	}

}
